def update_inventory_stock(session, item_id: str, qty: int):
    # Fetch stock record matching legacy attributes
    stock = session.query(WarehouseStock).filter_by(item_id=item_id).first()

    if stock and stock.quantity > qty:
        total_cost = stock.unit_price * qty
        stock.quantity -= qty
        session.commit()
        return {"status": "SUCCESS", "total_price": total_cost}
    else:
        return {"status": "INSUFFICIENT_STOCK", "total_price": 0.0}

